13	/// Contains discovered but unmapped members, ignored members, etc.
14	/// </summary>
15	/// <param name="unmappedSourceMemberNames">Source member names which are not used in a member mapping yet.</param>
16	/// <param name="unmappedTargetMemberNames">Target member names which are not used in a member mapping yet.</param>
17	/// <param name="targetMemberCaseMapping">A dictionary with all members of the target with a case-insensitive key comparer.</param>
18	/// <param name="targetMembers">All known target members.</param>
19	/// <param name="memberValueConfigsByRootTargetName">All value configurations by root target member names, which are not yet consumed.</param>
20	/// <param name="memberConfigsByRootTargetName">All configurations by root target member names, which are not yet consumed.</param>
21	/// <param name="ignoredSourceMemberNames">All ignored source members names.</param>
22	internal class MembersMappingState(
23	    HashSet<string> unmappedSourceMemberNames,
24	    HashSet<string> unmappedTargetMemberNames,
25	    IReadOnlyDictionary<string, string> targetMemberCaseMapping,
26	    Dictionary<string, IMappableMember> targetMembers,
27	    Dictionary<string, List<MemberValueMappingConfiguration>> memberValueConfigsByRootTargetName,
28	    Dictionary<string, List<MemberMappingConfiguration>> memberConfigsByRootTargetName,
29	    Dictionary<string, List<IMemberPathConfiguration>> configuredTargetMembersByRootName,
30	    HashSet<string> ignoredSourceMemberNames,
31	    ParameterScope parameterScope
32	)
33	{
34	    private readonly Dictionary<string, IMappableMember> _aliasedSourceMembers = new(StringComparer.OrdinalIgnoreCase);
35	
36	    /// <summary>
37	    /// All source member names that are not used in a member mapping (yet).
38	    /// </summary>
39	    private readonly HashSet<string> _unmappedSourceMemberNames = unmappedSourceMemberNames;
40	
41	    /// <summary>
