43	    /// </summary>
44	    private readonly HashSet<string> _unmappedTargetMemberNames = unmappedTargetMemberNames;
45	
46	    public ParameterScope ParameterScope => parameterScope;
47	
48	    public IReadOnlyCollection<string> IgnoredSourceMemberNames => ignoredSourceMemberNames;
