69	    public IEnumerable<IMappableMember> EnumerateUnmappedTargetMembers() => _unmappedTargetMemberNames.Select(x => targetMembers[x]);
70	
71	    public IEnumerable<IMappableMember> EnumerateUnmappedOrConfiguredTargetMembers()
72	    {
73	        return _unmappedTargetMemberNames
74	            .Concat(memberValueConfigsByRootTargetName.Keys)
75	            .Concat(memberConfigsByRootTargetName.Keys)
76	            .Distinct()
77	            .Select(targetMembers.GetValueOrDefault)
78	            .WhereNotNull()
79	            // Collect the enumeration since the source may be modified.
80	            // For more context see https://github.com/riok/mapperly/issues/1403#issuecomment-2267571805.
81	            .ToList();
82	    }
