    [Fact]
    public void AdditionalInitNullableIntParameter()
    {
        var source = TestSourceBuilder.MapperWithBodyAndTypes(
            "partial B Map(A src, int? value);",
            "class A { public string StringValue { get; set; } }",
            "class B { public string StringValue { get; set; } public string Value { get; init; } }"
        );

        TestHelper
            .GenerateMapper(source, TestHelperOptions.AllowDiagnostics)
            .Should()
            .HaveDiagnostic(
                DiagnosticDescriptors.NullableSourceValueToNonNullableTargetValue,
                "Mapping the nullable source property value of int? to the target property Value of B which is not nullable"
            )
