1	using Microsoft.CodeAnalysis;
2	using Riok.Mapperly.Descriptors.Mappings;
3	using Riok.Mapperly.Descriptors.Mappings.ExistingTarget;
4	using Riok.Mapperly.Diagnostics;
5	using Riok.Mapperly.Helpers;
6	
7	namespace Riok.Mapperly.Descriptors.MappingBuilders;
8	
9	public static class UseNamedMappingBuilder
10	{
11	    public static INewInstanceMapping? TryBuildMapping(MappingBuilderContext ctx)
12	    {
13	        if (ctx.MappingKey.Configuration.UseNamedMapping == null)
14	            return null;
15	
16	        var mapping = ctx.FindNamedMapping(ctx.MappingKey.Configuration.UseNamedMapping);
17	        if (mapping == null)
18	        {
19	            ctx.ReportDiagnostic(DiagnosticDescriptors.ReferencedMappingNotFound, ctx.MappingKey.Configuration.UseNamedMapping);
20	            return null;
21	        }
22	
23	        if (!ctx.ParameterScope.TryUseParameters(mapping))
24	        {
25	            ctx.ReportDiagnostic(DiagnosticDescriptors.NamedMappingParametersUnsatisfied, ctx.MappingKey.Configuration.UseNamedMapping);
26	            return null;
27	        }
28	
29	        var differentSourceType = !SymbolEqualityComparer.IncludeNullability.Equals(ctx.Source, mapping.SourceType);
30	        var differentTargetType = !SymbolEqualityComparer.IncludeNullability.Equals(ctx.Target, mapping.TargetType);
31	
32	        // use a delegate mapping,
33	        // otherwise the user-defined method mapping may get built twice
34	        // (if it is returned here directly, it is re-added to the mappings to be built)
35	        if (!differentSourceType && !differentTargetType)
36	            return new DelegateMapping(mapping.SourceType, mapping.TargetType, mapping);
37	
38	        if (differentSourceType)
39	        {
40	            mapping = TryMapSource(ctx, mapping);
41	            if (mapping == null)
42	                return null;
43	        }
44	
45	        return differentTargetType ? TryMapTarget(ctx, mapping) : mapping;
46	    }
47	
48	    public static IExistingTargetMapping? TryBuildExistingTargetMapping(MappingBuilderContext ctx)
49	    {
50	        if (ctx.MappingKey.Configuration.UseNamedMapping == null)
51	            return null;
52	
53	        var useNamedMapping = ctx.MappingKey.Configuration.UseNamedMapping;
54	        var existingTargetMapping = ctx.FindExistingTargetNamedMapping(useNamedMapping);
55	        if (existingTargetMapping is null)
56	            return null;
57	
58	        if (!ctx.ParameterScope.TryUseParameters(existingTargetMapping))
59	        {
60	            ctx.ReportDiagnostic(DiagnosticDescriptors.NamedMappingParametersUnsatisfied, useNamedMapping);
61	            return null;
62	        }
63	
64	        var source = ctx.Source;
65	        var target = ctx.Target;
66	
67	        var differentSourceType = !SymbolEqualityComparer.IncludeNullability.Equals(source, existingTargetMapping.SourceType);
68	        var differentTargetType = !SymbolEqualityComparer.IncludeNullability.Equals(target, existingTargetMapping.TargetType);
69	
