using Riok.Mapperly.Diagnostics;

namespace Riok.Mapperly.Tests.Mapping;

public class UserMethodAdditionalParametersTest
{
    [Fact]
    public Task AdditionalIntParameter()
    {
        var source = TestSourceBuilder.MapperWithBodyAndTypes(
            "partial B Map(A src, int value);",
            "class A { public string StringValue { get; set; } }",
            "class B { public string StringValue { get; set; } public string Value { get; set; } }"
        );

        return TestHelper.VerifyGenerator(source);
    }

    [Fact]
    public Task AdditionalNullableIntParameter()
    {
        var source = TestSourceBuilder.MapperWithBodyAndTypes(
            "partial B Map(A src, int? value);",
            "class A { public string StringValue { get; set; } }",
            "class B { public string StringValue { get; set; } public string Value { get; set; } }"
        );

        return TestHelper.VerifyGenerator(source);
    }

    [Fact]
    public void AdditionalParameterDoesNotOverrideSourceMemberInNestedGeneratedMapping()
    {
        var source = TestSourceBuilder.MapperWithBody(
            """
            public partial Data.Scenario Map(Model.Scenario source, int? id);
            """,
            additionalNamespaceContent:
                """
                namespace Model
                {
                    public class Scenario { public ScenarioAction Action { get; set; } }
                    public class ScenarioAction { public int Id { get; set; } public string Name { get; set; } }
                }

                namespace Data
                {
                    public class Scenario { public ScenarioAction Action { get; set; } }
                    public class ScenarioAction { public int Id { get; set; } public string Name { get; set; } }
                }
                """
        );

        TestHelper
            .GenerateMapper(source, TestHelperOptions.AllowDiagnostics)
            .Should()
            .HaveMethodBody(
                "MapToScenarioAction",
                """
                var target = new global::Data.ScenarioAction();
                target.Id = source.Id;
                target.Name = source.Name;
                return target;
                """
            );
    }

    [Fact]
    public void AdditionalInitParameter()
    {
        var source = TestSourceBuilder.MapperWithBodyAndTypes(
            "partial B Map(A src, int value);",
            "class A { public string StringValue { get; set; } }",
            "class B { public string StringValue { get; set; } public string Value { get; init; } }"
        );

        TestHelper
            .GenerateMapper(source)
            .Should()
            .HaveMapMethodBody(
                """
                var target = new global::B()
                {
                    Value = value.ToString(),
                };
                target.StringValue = src.StringValue;
                return target;
                """
            );
    }

    [Fact]
    public void AdditionalInitNullableIntParameter()
    {
        var source = TestSourceBuilder.MapperWithBodyAndTypes(
            "partial B Map(A src, int? value);",
            "class A { public string StringValue { get; set; } }",
            "class B { public string StringValue { get; set; } public string Value { get; init; } }"
        );

        TestHelper
            .GenerateMapper(source, TestHelperOptions.AllowDiagnostics)
            .Should()
            .HaveDiagnostic(
                DiagnosticDescriptors.NullableSourceValueToNonNullableTargetValue,
                "Mapping the nullable source property value of int? to the target property Value of B which is not nullable"
            )
            .HaveAssertedAllDiagnostics()
            .HaveMapMethodBody(
                """
                var target = new global::B()
                {
                    Value = value != null ? value.Value.ToString() : throw new global::System.ArgumentNullException(nameof(value.Value)),
                };
                target.StringValue = src.StringValue;
                return target;
                """
            );
    }

    [Fact]
    public Task TwoAdditionalParameters()
    {
        var source = TestSourceBuilder.MapperWithBodyAndTypes(
            "partial B Map(A src, int value, int id);",
            "class A { public string StringValue { get; set; } }",
            "class B { public string StringValue { get; set; } public string Value { get; init; } public int Id { get; init; } }"
        );

        return TestHelper.VerifyGenerator(source);
    }

    [Fact]
    public void PreferParameterOverSourceMember()
    {
        var source = TestSourceBuilder.MapperWithBodyAndTypes(
            "partial B Map(A src, int value);",
            "class A { public int Value { get; set; } }",
            "class B { public int Value { get; init; } }"
        );

        TestHelper
            .GenerateMapper(source, TestHelperOptions.AllowDiagnostics)
            .Should()
            .HaveDiagnostic(
                DiagnosticDescriptors.SourceMemberNotMapped,
                "The member Value on the mapping source type A is not mapped to any member on the mapping target type B"
            )
            .HaveAssertedAllDiagnostics()
            .HaveMapMethodBody(
                """
                var target = new global::B()
                {
                    Value = value,
                };
                return target;
                """
            );
    }

    [Fact]
    public void ClassFlattening()
    {
        var source = TestSourceBuilder.MapperWithBodyAndTypes(
            "partial B Map(A src, C nested);",
            "class A { public string StringValue { get; set; } }",
            "class B { public string StringValue { get; set; } public string NestedValue { get; init; } }",
            "class C { public int Value { get; init; } }"
        );

        TestHelper
            .GenerateMapper(source)
            .Should()
            .HaveMapMethodBody(
                """
