                {
                    NestedValue = nested.Value.ToString(),
                };
                target.StringValue = src.StringValue;
                return target;
                """
            );
    }

    [Fact]
    public void NullableClassFlattening()
    {
        var source = TestSourceBuilder.MapperWithBodyAndTypes(
            "partial B Map(A src, C? nested);",
            "class A { public string StringValue { get; set; } }",
            "class B { public string StringValue { get; set; } public string NestedValue { get; init; } }",
            "class C { public int Value { get; init; } }"
        );

        TestHelper
            .GenerateMapper(source, TestHelperOptions.AllowDiagnostics)
            .Should()
            .HaveDiagnostic(
                DiagnosticDescriptors.NullableSourceValueToNonNullableTargetValue,
                "Mapping the nullable source property nested.Value of C? to the target property NestedValue of B which is not nullable"
            )
            .HaveAssertedAllDiagnostics()
            .HaveMapMethodBody(
                """
                var target = new global::B()
                {
                    NestedValue = nested != null ? nested.Value.ToString() : throw new global::System.ArgumentNullException(nameof(nested.Value)),
                };
                target.StringValue = src.StringValue;
                return target;
                """
            );
    }

    [Fact]
    public void NullableClassToNullableFlattening()
    {
        var source = TestSourceBuilder.MapperWithBodyAndTypes(
            "partial B Map(A src, C? nested);",
            "class A { public string StringValue { get; set; } }",
            "class B { public string StringValue { get; set; } public int? NestedValue { get; init; } }",
            "class C { public int Value { get; init; } }"
        );

        TestHelper
            .GenerateMapper(source)
            .Should()
            .HaveMapMethodBody(
                """
                var target = new global::B()
                {
                    NestedValue = nested?.Value,
                };
                target.StringValue = src.StringValue;
                return target;
                """
            );
    }

